request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?node ?nodeName ?nodeType WHERE {
  ?node tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_a91555f6_d70d_4c6b_b0ad_d70ef853da6e> .
  ?node a ?nodeType .
  FILTER(?nodeType IN (bboExt:ChoreographyTask, bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
  OPTIONAL { ?node bbo:name ?nodeName . }

  # Check if there is any outgoing sequence flow
  FILTER NOT EXISTS {
    ?flow a bbo:SequenceFlow .
    ?flow bbo:has_sourceRef ?node .
  }
}
